  tool_usage: Record<string, number>;
  skill_usage: Record<string, number>;
  subagent_count: number;
  author: string;
  fetch_failed: boolean;
}

export interface CheckpointsCache {
  meta: CacheMeta;
  checkpoints: CheckpointMeta[];
}

