export const DATASET_COLORS = {
  purple: '#7c3aed',
  blue: '#1976d2',
  green: '#16a34a',
  amber: '#d97706',
  red: '#dc2626',
  gray: '#9ca3af',
  cyan: '#0891b2',
  pink: '#db2777',
  teal: '#0d9488',
  orange: '#ea580c',
} as const;

