1	import { useEffect, useRef } from 'react';
2	import { createChart, LineSeries } from 'lightweight-charts';
3	import type { IChartApi } from 'lightweight-charts';
4	import { LIGHT_LWC_COLORS } from '../../lib/light-chart-options';
5	
6	interface LightweightChartWrapperProps {
7	  id: string;
8	  series: Array<{ time: number; value: number }>;
9	  lineColor?: string;
10	  height?: number;
11	}
12	
13	export default function LightweightChartWrapper({
14	  id,
15	  series,
16	  lineColor = LIGHT_LWC_COLORS.lineColor,
17	  height = 200,
18	}: LightweightChartWrapperProps) {
19	  const containerRef = useRef<HTMLDivElement>(null);
20	  const chartRef = useRef<IChartApi | null>(null);
21	
22	  useEffect(() => {
23	    if (!containerRef.current) return;
24	
25	    chartRef.current?.remove();
26	    while (containerRef.current.firstChild) {
27	      containerRef.current.removeChild(containerRef.current.firstChild);
28	    }
29	
30	    if (!series.length) return;
31	
32	    const deduped = series.filter((p, i) => i === 0 || p.time !== series[i - 1].time);
33	
34	    const chart = createChart(containerRef.current, {
35	      layout: { background: { color: 'transparent' }, textColor: LIGHT_LWC_COLORS.textColor },
36	      grid: {
37	        vertLines: { color: LIGHT_LWC_COLORS.gridLinesColor },
38	        horzLines: { color: LIGHT_LWC_COLORS.gridLinesColor },
39	      },
40	      rightPriceScale: { borderVisible: false },
41	      timeScale: { borderVisible: false, timeVisible: false },
42	      handleScroll: false,
43	      handleScale: false,
44	      autoSize: true,
45	    });
46	
47	    const s = chart.addSeries(LineSeries, {
48	      color: lineColor,
49	      lineWidth: 2,
50	      pointMarkersVisible: true,
