1	import { useState, useCallback, useMemo } from 'react';
2	import { ThemeProvider } from '@mui/material/styles';
3	import CssBaseline from '@mui/material/CssBaseline';
4	import Paper from '@mui/material/Paper';
5	import Typography from '@mui/material/Typography';
6	import Box from '@mui/material/Box';
7	import Button from '@mui/material/Button';
8	import Select from '@mui/material/Select';
9	import MenuItem from '@mui/material/MenuItem';
10	import FormControl from '@mui/material/FormControl';
11	import InputLabel from '@mui/material/InputLabel';
12	import TextField from '@mui/material/TextField';
13	import { lightTheme } from '../../lib/mui-theme';
14	import { filterRenderableCheckpoints, formatCheckpointOptionLabel, formatGeneratedAt } from '../../lib/utils/ai-metrics-utils';
15	import { fetchCheckpointsCache } from '../../lib/utils/github-checkpoints';
16	import type { CheckpointMeta, CheckpointsCache } from '../../lib/utils/ai-metrics-utils';
17	
18	import AttributionSection from './AttributionSection';
19	import TokenSection from './TokenSection';
20	import QualitySection from './QualitySection';
21	import BehavioralSection from './BehavioralSection';
22	import TemporalSection from './TemporalSection';
23	import QualityDebtSection from './QualityDebtSection';
24	
25	interface CacheMeta {
26	  repo: string;
27	  branch: string;
28	  generatedAt: string;
29	  checkpointCount: number;
30	}
31	
32	interface Props {
33	  initialCheckpoints: CheckpointMeta[];
34	  meta: CacheMeta | null;
35	  source: { repo: string; branch: string };
36	}
37	
38	export default function AiMetricsDashboard({ initialCheckpoints, meta, source }: Props) {
39	  const [allCheckpoints, setAllCheckpoints] = useState(initialCheckpoints);
40	  const [selectedValue, setSelectedValue] = useState('all');
41	  const [selectedAuthor, setSelectedAuthor] = useState('all');
42	  const [dateFrom, setDateFrom] = useState('');
43	  const [dateTo, setDateTo] = useState('');
44	  const [cacheMeta, setCacheMeta] = useState(meta);
45	  const [refreshStatus, setRefreshStatus] = useState(
46	    meta === null
47	      ? 'No cached commit snapshot is loaded. Use the refresh button to fetch data directly from GitHub.'
48	      : 'Dashboard is showing the cached commit snapshot until you refresh.',
49	  );
50	  const [refreshTone, setRefreshTone] = useState<'default' | 'success' | 'error'>('default');
51	  const [isRefreshing, setIsRefreshing] = useState(false);
52	
53	  const sorted = useMemo(
54	    () => [...allCheckpoints].sort((a, b) => new Date(a.commit_date).getTime() - new Date(b.commit_date).getTime()),
55	    [allCheckpoints],
56	  );
57	
58	  const uniqueAuthors = useMemo(
59	    () => [...new Set(allCheckpoints.map((c) => c.author).filter((a) => a && a !== 'unknown'))].sort(),
60	    [allCheckpoints],
61	  );
62	
63	  const selectedCheckpoints = useMemo(() => {
64	    let filtered = allCheckpoints;
65	    if (selectedValue !== 'all') filtered = filtered.filter((c) => c.checkpoint_id === selectedValue);
66	    if (selectedAuthor !== 'all') filtered = filtered.filter((c) => c.author === selectedAuthor);
67	    if (dateFrom) {
68	      const from = new Date(dateFrom).getTime();
69	      filtered = filtered.filter((c) => new Date(c.commit_date).getTime() >= from);
70	    }
71	    if (dateTo) {
72	      const to = new Date(dateTo).getTime() + 86_400_000; // include the whole "to" day
73	      filtered = filtered.filter((c) => new Date(c.commit_date).getTime() < to);
74	    }
75	    return filtered;
76	  }, [allCheckpoints, selectedValue, selectedAuthor, dateFrom, dateTo]);
77	
78	  const handleRefresh = useCallback(async () => {
79	    setIsRefreshing(true);
80	    setRefreshStatus('Fetching the latest commit data from GitHub...');
81	    setRefreshTone('default');
82	
83	    try {
84	      const result = await fetchCheckpointsCache();
85	      const filtered = filterRenderableCheckpoints(result.cache.checkpoints);
86	      setAllCheckpoints(filtered);
87	      setCacheMeta(result.cache.meta);
88	
89	      const stillExists = filtered.some((c) => c.checkpoint_id === selectedValue);
90	      if (!stillExists && selectedValue !== 'all') setSelectedValue('all');
91	
92	      setRefreshStatus(
93	        `Loaded ${result.cache.meta.checkpointCount} commits in ${(result.elapsedMs / 1000).toFixed(1)}s across ${result.apiCallCount} GitHub API calls.`,
94	      );
95	      setRefreshTone('success');
96	    } catch (error) {
97	      const message = error instanceof Error ? error.message : 'Unknown error';
98	      setRefreshStatus(`Refresh failed: ${message}`);
99	      setRefreshTone('error');
100	    } finally {
101	      setIsRefreshing(false);
102	    }
103	  }, [selectedValue]);
104	
105	  const statusColor = refreshTone === 'success' ? 'success.main' : refreshTone === 'error' ? 'error.main' : 'text.disabled';
106	
107	  return (
108	    <ThemeProvider theme={lightTheme}>
109	      <CssBaseline />
110	
111	      {/* Header */}
112	      <Paper sx={{ p: 2.5, mb: 4 }}>
113	        {/* Row 1: Metadata + Refresh */}
114	        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 2 }}>
115	          <Box sx={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 3 }}>
116	            <Box>
117	              <Typography variant="caption" color="text.disabled">Repository</Typography>
118	              <Typography variant="body2" color="primary" sx={{ fontWeight: 500 }}>
119	                {cacheMeta?.repo ?? source.repo}
120	              </Typography>
121	            </Box>
122	            <Box>
123	              <Typography variant="caption" color="text.disabled">Branch</Typography>
124	              <Typography variant="body2" color="text.secondary">
125	                {cacheMeta?.branch ?? source.branch}
126	              </Typography>
127	            </Box>
128	            <Box>
129	              <Typography variant="caption" color="text.disabled">Commits</Typography>
130	              <Typography variant="body2" sx={{ fontWeight: 600 }}>
131	                {cacheMeta?.checkpointCount ?? 0}
132	              </Typography>
133	            </Box>
134	            <Box>
135	              <Typography variant="caption" color="text.disabled">Generated</Typography>
136	              <Typography variant="body2" color="text.secondary">
137	                {formatGeneratedAt(cacheMeta?.generatedAt)}
138	              </Typography>
139	            </Box>
140	          </Box>
141	          <Button
142	            variant="outlined"
143	            onClick={handleRefresh}
144	            disabled={isRefreshing}
145	            sx={{ whiteSpace: 'nowrap' }}
146	          >
147	            {isRefreshing ? 'Refreshing...' : 'Refresh From GitHub'}
148	          </Button>
149	        </Box>
150	
151	        {/* Row 2: Filters */}
152	        <Box sx={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 2, mt: 2 }}>
153	          <FormControl size="small" sx={{ minWidth: 200 }}>
154	            <InputLabel>View</InputLabel>
155	            <Select
156	              label="View"
157	              value={selectedValue}
158	              onChange={(e) => setSelectedValue(e.target.value)}
159	              disabled={allCheckpoints.length === 0}
160	            >
161	              <MenuItem value="all">All Commits</MenuItem>
162	              {sorted.map((cp) => (
163	                <MenuItem key={cp.checkpoint_id} value={cp.checkpoint_id}>
164	                  {formatCheckpointOptionLabel(cp)}
165	                </MenuItem>
166	              ))}
167	            </Select>
168	          </FormControl>
169	          {uniqueAuthors.length > 0 && (
170	            <FormControl size="small" sx={{ minWidth: 180 }}>
171	              <InputLabel>Developer</InputLabel>
172	              <Select
173	                label="Developer"
174	                value={selectedAuthor}
175	                onChange={(e) => setSelectedAuthor(e.target.value)}
176	              >
177	                <MenuItem value="all">All Developers</MenuItem>
178	                {uniqueAuthors.map((author) => (
179	                  <MenuItem key={author} value={author}>{author}</MenuItem>
180	                ))}
181	              </Select>
182	            </FormControl>
183	          )}
184	          <TextField
185	            type="date"
186	            label="From"
187	            size="small"
188	            value={dateFrom}
189	            onChange={(e) => setDateFrom(e.target.value)}
190	            slotProps={{ inputLabel: { shrink: true } }}
191	            sx={{ width: 160 }}
192	          />
193	          <TextField
194	            type="date"
195	            label="To"
196	            size="small"
197	            value={dateTo}
198	            onChange={(e) => setDateTo(e.target.value)}
199	            slotProps={{ inputLabel: { shrink: true } }}
200	            sx={{ width: 160 }}
201	          />
202	        </Box>
203	
204	        {/* Row 3: Status */}
205	        <Box sx={{ mt: 1.5, display: 'flex', flexWrap: 'wrap', gap: 2, alignItems: 'center' }}>
206	          <Typography variant="caption" color={statusColor}>
207	            {refreshStatus}
208	          </Typography>
209	          <Typography variant="caption" color="text.disabled">
210	            GitHub API limit is 60 requests per hour when used without a token.
211	          </Typography>
212	        </Box>
213	      </Paper>
214	
215	      {/* Metrics Grid */}
216	      <Box
217	        sx={{
218	          display: 'grid',
219	          gridTemplateColumns: { xs: '1fr', md: 'repeat(2, 1fr)', lg: 'repeat(3, 1fr)' },
220	          gap: 3,
221	        }}
222	      >
223	        <AttributionSection checkpoints={selectedCheckpoints} />
224	        <TokenSection checkpoints={selectedCheckpoints} />
225	        <QualitySection checkpoints={selectedCheckpoints} />
226	        <BehavioralSection checkpoints={selectedCheckpoints} />
227	        <TemporalSection checkpoints={selectedCheckpoints} />
228	        <QualityDebtSection checkpoints={selectedCheckpoints} />
229	      </Box>
230	    </ThemeProvider>
231	  );
232	}
