54	function decodeBase64Utf8(content: string): string {
55	  const normalized = content.replace(/[\r\n]/g, '');
56	
57	  if (typeof globalThis.atob === 'function') {
58	    const binary = globalThis.atob(normalized);
59	    const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
60	    return new TextDecoder().decode(bytes);
61	  }
62	
63	  const bufferCtor = (globalThis as {
64	    Buffer?: {
65	      from(input: string, encoding: string): { toString(encoding: string): string };
66	    };
67	  }).Buffer;
68	
69	  if (bufferCtor) {
70	    return bufferCtor.from(normalized, 'base64').toString('utf-8');
71	  }
72	
73	  throw new Error('No base64 decoder available in this runtime');
74	}
