76	export function extractTranscriptData(jsonlContent: string): TranscriptExtraction {
77	  const bmad_commands: Record<string, number> = {};
78	  const models: Record<string, number> = {};
79	  const tool_usage: Record<string, number> = {};
80	  const skill_usage: Record<string, number> = {};
81	  let subagent_count = 0;
82	  let first_prompt = '';
83	
84	  const commandRegex = /^\/[a-z][a-z0-9-]*/;
85	  const commandTagRegex = /<command-name>(\/[a-z][a-z0-9-]*)<\/command-name>/;
86	
87	  for (const line of jsonlContent.split('\n')) {
88	    if (!line.trim()) continue;
89	
90	    let parsed: unknown;
91	    try {
92	      parsed = JSON.parse(line);
93	    } catch {
94	      continue;
95	    }
96	
97	    if (!isRecord(parsed)) continue;
98	
99	    const messageRaw = isRecord(parsed['message']) ? parsed['message'] : null;
100	
101	    if (parsed['type'] === 'assistant' && messageRaw) {
102	      const model = getString(messageRaw, 'model');
103	      if (model) {
104	        models[model] = (models[model] ?? 0) + 1;
105	      }
106	
107	      const contentArr = Array.isArray(messageRaw['content']) ? messageRaw['content'] : [];
108	      for (const block of contentArr) {
109	        if (!isRecord(block) || block['type'] !== 'tool_use') continue;
110	        const toolName = getString(block, 'name') ?? 'unknown';
111	        tool_usage[toolName] = (tool_usage[toolName] ?? 0) + 1;
112	
113	        const blockInput = isRecord(block['input']) ? block['input'] : null;
114	        if (toolName === 'Skill' && blockInput) {
115	          const skillId = getString(blockInput, 'skill') ?? getString(blockInput, 'name') ?? 'unknown';
116	          skill_usage[skillId] = (skill_usage[skillId] ?? 0) + 1;
117	        }
118	
119	        if (toolName === 'Task' || toolName === 'Agent') {
120	          subagent_count++;
121	        }
122	      }
123	    }
124	
125	    if (parsed['type'] === 'user') {
126	      if (parsed['isMeta'] === true) continue;
127	
128	      const content =
129	        (messageRaw ? getString(messageRaw, 'content') : null) ??
130	        getString(parsed, 'content') ??
131	        getString(parsed, 'prompt') ??
132	        '';
133	
134	      if (!first_prompt && content.trim()) {
135	        const tagMatch = /<command-name>(\/[^\s<]+)<\/command-name>/.exec(content);
136	        first_prompt = tagMatch
137	          ? tagMatch[1]
138	          : content.trim().split('\n')[0]?.slice(0, PROMPT_TXT_MAX_LEN) ?? '';
139	      }
140	
141	      const tagMatch = commandTagRegex.exec(content);
142	      const command = tagMatch
143	        ? tagMatch[1]
144	        : commandRegex.exec(content.trimStart())?.[0];
145	
146	      if (command) {
147	        bmad_commands[command] = (bmad_commands[command] ?? 0) + 1;
148	      }
149	    }
150	  }
151	
152	  return { bmad_commands, models, first_prompt, tool_usage, skill_usage, subagent_count };
153	}
