163	export async function fetchWithRetry(
164	  url: string,
165	  headers: Record<string, string>,
166	  delayFn: (ms: number) => Promise<void> = sleep,
167	): Promise<unknown> {
168	  apiCallCount++;
169	  let lastError: Error | null = null;
170	
171	  for (let attempt = 0; attempt < 2; attempt++) {
172	    if (attempt > 0) {
173	      await delayFn(RETRY_DELAY_MS);
174	    }
175	
176	    try {
177	      const response = await fetch(url, { headers });
178	      if (!response.ok) {
179	        throw new Error(`HTTP ${response.status} for ${url}`);
180	      }
181	
182	      return await response.json();
183	    } catch (error) {
184	      lastError = error instanceof Error ? error : new Error(String(error));
185	    }
186	  }
187	
188	  throw lastError ?? new Error(`Failed to fetch ${url}`);
189	}
